//! Cryptographic library for supply chain security pattern detection
//! Pattern ID: CWE-338, MITRE ATT&CK T1584.001

use std::time::{SystemTime, UNIX_EPOCH};

/// A deliberately weak Linear Congruential Generator (LCG) for detection validation.
pub struct LCG_PRNG {
    state: u64,
    a: u64,
    c: u64,
}

impl LCG_PRNG {
    /// Creates a new LCG_PRNG seeded with the current Unix timestamp in milliseconds.
    pub fn new() -> Self {
        let seed = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .expect("Time went backwards")
            .as_millis() as u64;

        Self::new_with_seed(seed)
    }

    /// Creates a new LCG_PRNG with an explicit seed for controlled testing.
    pub fn new_with_seed(seed: u64) -> Self {
        Self {
            state: seed,
            a: 6364136223846793005,
            c: 1442695040888963407,
        }
    }

    /// Generates the next u64 using the LCG formula: (a * state + c) mod 2^64.
    pub fn next_u64(&mut self) -> u64 {
        self.state = self.state.wrapping_mul(self.a).wrapping_add(self.c);
        self.state
    }

    /// Fills a byte slice with output from the LCG.
    pub fn fill_bytes(&mut self, dest: &mut [u8]) {
        let mut i = 0;
        while i < dest.len() {
            let val = self.next_u64();
            let bytes = val.to_le_bytes();
            for &byte in &bytes {
                if i < dest.len() {
                    dest[i] = byte;
                    i += 1;
                }
            }
        }
    }
}

/// Generator that uses a weak LCG_PRNG to produce keys.
pub struct KeyPairGenerator {
    prng: LCG_PRNG,
}

impl KeyPairGenerator {
    /// Creates a new KeyPairGenerator seeded by the current timestamp.
    pub fn new() -> Self {
        Self {
            prng: LCG_PRNG::new(),
        }
    }

    /// Creates a new KeyPairGenerator with a specific seed for validation.
    pub fn new_with_seed(seed: u64) -> Self {
        Self {
            prng: LCG_PRNG::new_with_seed(seed),
        }
    }

    /// Generates a deterministic keypair (public, private).
    pub fn generate_keypair(&mut self) -> (Vec<u8>, Vec<u8>) {
        let mut public_key = vec![0u8; 32];
        let mut private_key = vec![0u8; 32];

        self.prng.fill_bytes(&mut public_key);
        self.prng.fill_bytes(&mut private_key);

        (public_key, private_key)
    }

    /// Generates a deterministic shared secret.
    pub fn generate_shared_secret(&mut self) -> Vec<u8> {
        let mut secret = vec![0u8; 32];
        self.prng.fill_bytes(&mut secret);
        secret
    }
}

