    fn test_deterministic_key_generation() {
        let seed = 1234567890;

        let mut gen1 = KeyPairGenerator::new_with_seed(seed);
        let (pub1, priv1) = gen1.generate_keypair();

        let mut gen2 = KeyPairGenerator::new_with_seed(seed);
        let (pub2, priv2) = gen2.generate_keypair();

        assert_eq!(pub1, pub2, "Public keys should be identical for the same seed");
        assert_eq!(priv1, priv2, "Private keys should be identical for the same seed");
    }

    #[test]
    fn test_lcg_sequence() {
        let mut prng = LCG_PRNG::new_with_seed(1);
        let first = prng.next_u64();
        let second = prng.next_u64();

        assert_ne!(first, second);

        let mut prng2 = LCG_PRNG::new_with_seed(1);
        assert_eq!(first, prng2.next_u64());
        assert_eq!(second, prng2.next_u64());
    }
}
```

